// src/three/ModelLoader.js
// Handles efficient loading of 3D models with caching

import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader';
export class ModelLoader {
  constructor() {
    // Initialize loaders
    this.gltfLoader = new GLTFLoader();

    // Add DRACO decoder for compressed models
    this.dracoLoader = new DRACOLoader();
    this.dracoLoader.setDecoderPath('/assets/draco/');
    this.gltfLoader.setDRACOLoader(this.dracoLoader);

    // Model cache to avoid reloading the same models
    this.modelCache = new Map();

    // Default model catalogue - maps model types to file paths
    this.modelCatalogue = {
      'treadmill': '/assets/models/treadmill.glb',
      'bench': '/assets/models/bench.glb',
      'dumbbellRack': '/assets/models/dumbbell-rack.glb',
      'squat-rack': '/assets/models/squat-rack.glb',
      'elliptical': '/assets/models/elliptical.glb',
      'rowing-machine': '/assets/models/rowing-machine.glb',
      'yoga-mat': '/assets/models/yoga-mat.glb',
      'exercise-bike': '/assets/models/exercise-bike.glb'
    };

    // Map of model types to their physical dimensions (in meters)
    // Used for proper placement and collision detection
    this.modelDimensions = {
      'treadmill': {
        width: 0.9,
        height: 1.5,
        depth: 1.8
      },
      'bench': {
        width: 0.6,
        height: 0.5,
        depth: 1.2
      },
      'dumbbellRack': {
        width: 1.2,
        height: 0.9,
        depth: 0.6
      },
      'squat-rack': {
        width: 1.2,
        height: 2.1,
        depth: 1.2
      },
      'elliptical': {
        width: 0.7,
        height: 1.7,
        depth: 1.4
      },
      'rowing-machine': {
        width: 0.5,
        height: 0.9,
        depth: 2.4
      },
      'yoga-mat': {
        width: 0.6,
        height: 0.02,
        depth: 1.8
      },
      'exercise-bike': {
        width: 0.6,
        height: 1.2,
        depth: 1.1
      }
    };

    // Loading manager for tracking load progress
    this.loadingManager = new THREE.LoadingManager();
    this.loadingManager.onProgress = (url, loaded, total) => {
      const progress = Math.round(loaded / total * 100);
      // Dispatch progress event
      const event = new CustomEvent('model-load-progress', {
        detail: {
          url,
          loaded,
          total,
          progress
        }
      });
      window.dispatchEvent(event);
    };
    this.gltfLoader.manager = this.loadingManager;
  }

  /**
   * Load a model by type
   * @param {string} modelType - Type of model from the catalogue
   * @param {Function} callback - Function to call with the loaded model
   */
  load(modelType, callback) {
    // Check if model type exists in catalogue
    if (!this.modelCatalogue[modelType]) {
      console.error(`Model type "${modelType}" not found in catalogue`);
      return;
    }
    const modelPath = this.modelCatalogue[modelType];

    // Check if model is already cached
    if (this.modelCache.has(modelType)) {
      // Create a clone of the cached model
      const cachedModel = this.modelCache.get(modelType);
      const clonedModel = this.cloneModel(cachedModel);

      // Apply any necessary post-processing
      this.postProcessModel(clonedModel, modelType);

      // Call the callback with the cloned model
      callback(clonedModel);
      return;
    }

    // Model not cached, load it
    this.gltfLoader.load(modelPath, gltf => {
      // Process and prepare the model
      const model = this.processLoadedModel(gltf, modelType);

      // Cache the model for future use
      this.modelCache.set(modelType, model.clone());

      // Call the callback with the model
      callback(model);
    },
    // onProgress callback
    xhr => {
      // console.log(`${modelType} ${Math.round((xhr.loaded / xhr.total) * 100)}% loaded`);
    },
    // onError callback
    error => {
      console.error(`Error loading model ${modelType}:`, error);
    });
  }

  /**
   * Process a loaded GLTF model
   * @param {Object} gltf - The loaded GLTF object
   * @param {string} modelType - Type of model
   * @returns {THREE.Object3D} - Processed model
   */
  processLoadedModel(gltf, modelType) {
    const model = gltf.scene;

    // Add shadow casting to all meshes
    model.traverse(node => {
      if (node.isMesh) {
        node.castShadow = true;
        node.receiveShadow = true;

        // Optimize materials if needed
        this.optimizeMaterial(node.material);
      }
    });

    // Set model properties
    model.userData.type = modelType;
    model.userData.isModelRoot = true;
    model.userData.dimensions = this.modelDimensions[modelType];

    // Center model on its base
    this.centerModel(model);
    return model;
  }

  /**
   * Center the model on its base for proper placement
   * @param {THREE.Object3D} model - The model to center
   */
  centerModel(model) {
    // Calculate bounding box
    const bbox = new THREE.Box3().setFromObject(model);
    const center = new THREE.Vector3();

    // Get dimensions
    bbox.getCenter(center);
    const width = bbox.max.x - bbox.min.x;
    const height = bbox.max.y - bbox.min.y;
    const depth = bbox.max.z - bbox.min.z;

    // Center horizontally, place bottom at y=0
    model.position.x = -center.x;
    model.position.y = -bbox.min.y;
    model.position.z = -center.z;

    // Update the model's dimensions in userData
    model.userData.actualDimensions = {
      width,
      height,
      depth
    };
  }

  /**
   * Optimize material for better performance
   * @param {THREE.Material} material - Material to optimize
   */
  optimizeMaterial(material) {
    if (!material) return;

    // If it's an array of materials, optimize each one
    if (Array.isArray(material)) {
      material.forEach(mat => this.optimizeMaterial(mat));
      return;
    }

    // Set reasonable defaults for better performance
    material.side = THREE.FrontSide; // Render only front face

    // Optimize textures if present
    if (material.map) {
      material.map.anisotropy = 4; // Improve texture quality with reasonable performance
    }
  }

  /**
   * Clone a model with its materials and textures
   * @param {THREE.Object3D} model - The model to clone
   * @returns {THREE.Object3D} - Cloned model
   */
  cloneModel(model) {
    const clone = model.clone();

    // Clone materials to avoid shared materials between instances
    clone.traverse(node => {
      if (node.isMesh && node.material) {
        if (Array.isArray(node.material)) {
          node.material = node.material.map(mat => mat.clone());
        } else {
          node.material = node.material.clone();
        }
      }
    });

    // Copy userData
    clone.userData = JSON.parse(JSON.stringify(model.userData));
    return clone;
  }

  /**
   * Apply any post-processing to a model
   * @param {THREE.Object3D} model - The model to process
   * @param {string} modelType - Type of model
   */
  postProcessModel(model, modelType) {
    // Apply any model-specific transformations or adjustments
    switch (modelType) {
      case 'treadmill':
        // Example: Set up animation for treadmill belt
        model.traverse(node => {
          if (node.name === 'TreadmillBelt') {
            node.userData.animatable = true;
            node.userData.animationSpeed = 0.05;
          }
        });
        break;
      case 'exercise-bike':
        // Example: Set up animation for bike pedals
        model.traverse(node => {
          if (node.name === 'Pedals') {
            node.userData.animatable = true;
            node.userData.animationSpeed = 0.1;
            node.userData.rotationAxis = 'z';
          }
        });
        break;
    }
  }

  /**
   * Duplicate an existing model
   * @param {THREE.Object3D} model - The model to duplicate
   * @param {Function} callback - Function to call with the duplicated model
   */
  duplicate(model, callback) {
    if (!model || !model.userData || !model.userData.type) {
      console.error('Cannot duplicate model: invalid model or missing type');
      return;
    }
    const modelType = model.userData.type;

    // If the model is cached, use the cached version as template
    if (this.modelCache.has(modelType)) {
      const cachedModel = this.modelCache.get(modelType);
      const duplicatedModel = this.cloneModel(cachedModel);

      // Copy position, rotation, and scale from the original
      duplicatedModel.position.copy(model.position);
      duplicatedModel.rotation.copy(model.rotation);
      duplicatedModel.scale.copy(model.scale);

      // Apply post-processing
      this.postProcessModel(duplicatedModel, modelType);
      callback(duplicatedModel);
    } else {
      // If not cached, make a direct clone
      const duplicatedModel = this.cloneModel(model);
      callback(duplicatedModel);
    }
  }

  /**
   * Preload models for faster access later
   * @param {Array} modelTypes - Array of model types to preload
   * @param {Function} onComplete - Callback when all models are loaded
   */
  preloadModels(modelTypes, onComplete = null) {
    if (!modelTypes || modelTypes.length === 0) {
      if (onComplete) onComplete();
      return;
    }
    let loadedCount = 0;
    const totalCount = modelTypes.length;
    modelTypes.forEach(modelType => {
      if (!this.modelCatalogue[modelType]) {
        console.warn(`Model type "${modelType}" not found in catalogue, skipping preload`);
        loadedCount++;
        if (loadedCount === totalCount && onComplete) onComplete();
        return;
      }

      // Skip if already cached
      if (this.modelCache.has(modelType)) {
        loadedCount++;
        if (loadedCount === totalCount && onComplete) onComplete();
        return;
      }

      // Load the model
      this.load(modelType, model => {
        loadedCount++;
        if (loadedCount === totalCount && onComplete) onComplete();
      });
    });
  }

  /**
   * Get the dimensions of a model type
   * @param {string} modelType - Type of model
   * @returns {Object} - Object with width, height, depth properties
   */
  getModelDimensions(modelType) {
    return this.modelDimensions[modelType] || null;
  }

  /**
   * Clear the model cache to free memory
   */
  clearCache() {
    this.modelCache.clear();
  }
}

